protocol Describable { func kind() -> String }
extension Describable {
    func kind() -> String { "generic" }
    func label() -> String { "unlabeled" }   // extension-only
}
struct Widget: Describable {
    func kind() -> String { "widget" }
    func label() -> String { "shiny widget" }
}
let d: Describable = Widget()
print(d.label())
